import { Box, Button, Container, FormControl, FormControlLabel, FormLabel, Grid, makeStyles, Paper, Radio, RadioGroup, TextField, Typography } from '@material-ui/core';
import { AddRounded, CheckBox } from '@material-ui/icons';
import React from 'react';

const useStyle = makeStyles(theme => {
  return {
    paper: {
      padding: theme.spacing(2),
      borderTop: '10px solid #162276'
    },
    quizPaper: {
      padding: theme.spacing(2),
      borderLeft: '10px solid #162276'
    }
  }
})

const CreateQuiz = () => {
  const classes = useStyle()

  const [value, setValue] = React.useState('female');

  const handleChange = (event) => {
    setValue(event.target.value);
  };


  return (
    <Container>
      <Box mb={2}>
        Create Quiz
        <Paper className={classes.paper}>
          <TextField placeholder='Quiz title' fullWidth />
          <TextField placeholder='Description' fullWidth />
        </Paper>
      </Box>
      <Box mb={2}>
        <Paper className={classes.quizPaper}>
          <FormControl component="fieldset">
            <FormLabel component="legend">Gender</FormLabel>
            <RadioGroup aria-label="gender" name="gender1" value={value} onChange={handleChange}>
              <FormControlLabel value="female" control={<Radio />} label="Female" />
            </RadioGroup>
          </FormControl>
          <Radio />
        </Paper>
      </Box>
    </Container>
  );
}

export default CreateQuiz;
